parameters.jsCode:
const rows = $input.all().map(x => x.json || {});
const now = new Date();
const from = new Date(now);
from.setDate(now.getDate() - 7);

function truthy(v) {
  if (v === true || v === 1) return true;
  return ['true','1','y','yes','예','o'].includes(String(v ?? '').trim().toLowerCase());
}
function split(v) {
  if (Array.isArray(v)) return v.map(String).map(x => x.trim()).filter(Boolean);
  return String(v ?? '').split(/[,，\n]+/).map(x => x.trim()).filter(Boolean);
}
function toMDY(d) {
  return `${d.getMonth()+1}/${d.getDate()}/${d.getFullYear()}`;
}

const allowed = new Set(['CLIENT_WATCH']);
const activeRows = rows.filter(r => {
  const active = r.active === '' || r.active === undefined ? true : truthy(r.active);
  return active &&
    allowed.has(String(r.section || '').trim().toUpperCase()) &&
    String(r.keyword || '').trim();
});

const jobs = activeRows.map((row, idx) => {
  const section = String(row.section).trim().toUpperCase();
  const category = String(row.category || '').trim();
  const target = String(row.target || '').trim();
  const keyword = String(row.keyword || '').trim();
  const includeTerms = split(row.include_terms);
  const excludeTerms = split(row.exclude_terms);

  // 실제 검색어에는 target + keyword만 사용
  const q = [target, keyword].filter(Boolean).join(' ').trim();

  return {
    job_id: `CW-${idx+1}`,
    section,
    category,
    target,
    keyword,
    include_terms: includeTerms,
    exclude_terms: excludeTerms,
    q,
    gl: 'kr',
    hl: 'ko',
    num: 20,
    tbs: `cdr:1,cd_min:${toMDY(from)},cd_max:${toMDY(now)}`,
    naver_display: 30,
    naver_sort: 'date',
    period_start: from.toISOString().slice(0,10),
    period_end: now.toISOString().slice(0,10)
  };
});

if (!jobs.length) throw new Error('활성화된 CLIENT_WATCH 키워드가 없습니다.');
return jobs.map(job => ({ json: job }));

const jobs = $('3-A-2. Code - CLIENT_WATCH 검색 Job 생성').all();
const job = jobs[$itemIndex]?.json || {};

if (!job.job_id || job.section !== 'CLIENT_WATCH') {
  throw new Error(
    'CLIENT_WATCH Job 복원 실패: 입력 인덱스 ' + $itemIndex +
    ', 조회된 Job=' + JSON.stringify(job).slice(0, 500)
  );
}

return {
  json: {
    job,
    naver_response: $json || {}
  },
  pairedItem: { item: $itemIndex }
};

const packedItems = $('3-A-5. Code - CLIENT_WATCH Naver 결과 + Job 보존').all();
const packed = packedItems[$itemIndex]?.json || {};

if (!packed.job?.job_id || packed.job.section !== 'CLIENT_WATCH') {
  throw new Error(
    'CLIENT_WATCH Naver 결과와 Serper 결과 통합 실패: 입력 인덱스 ' + $itemIndex +
    ', 보존 데이터=' + JSON.stringify(packed).slice(0, 700)
  );
}

return {
  json: {
    job: packed.job,
    naver_response: packed.naver_response || {},
    serper_response: $json || {}
  },
  pairedItem: { item: $itemIndex }
};

const inputs = $input.all().map(x => x.json || {});
const candidates = [];
const branchSection = 'CLIENT_WATCH';

if (!inputs.length) {
  throw new Error(branchSection + ' 통합 입력이 0건입니다. Naver/Serper 통합 노드 연결을 확인하세요.');
}

const invalidInputs = inputs.filter(x => !x.job?.job_id || x.job.section !== branchSection);
if (invalidInputs.length) {
  throw new Error(
    branchSection + ' 데이터 전달 오류: 전체 ' + inputs.length + '건 중 ' +
    invalidInputs.length + '건에 유효한 Job이 없습니다. 샘플=' +
    JSON.stringify(invalidInputs[0]).slice(0, 900)
  );
}

const naverErrorCount = inputs.filter(x => x.naver_response?.error).length;
const serperErrorCount = inputs.filter(x => x.serper_response?.error).length;

function stripHtml(v) {
  return String(v || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, '&')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}
function norm(v) {
  return stripHtml(v).toLowerCase();
}
function contains(text, term) {
  const t = norm(term);
  return t ? norm(text).includes(t) : false;
}
function daysAgo(v) {
  if (!v) return 99;
  const d = new Date(v);
  if (isNaN(d.getTime())) return 99;
  return Math.floor((Date.now() - d.getTime()) / 86400000);
}
function dateValue(v) {
  const d = new Date(v || 0);
  return isNaN(d.getTime()) ? 0 : d.getTime();
}

const STOP = new Set([
  '삼성전자','삼성','전자','기업','관련','대한','이번','최근','통해','위해','있는','한다',
  '했다','밝혔다','추진','계획','사업','시장','산업','정부','국내','글로벌','뉴스',
  '기자','단독','속보','전망','발표','확대','강화','지원','구축','운영','전환'
]);

function tokens(v) {
  return norm(v)
    .replace(/[^0-9a-z가-힣%]/g, ' ')
    .split(/\s+/)
    .map(x => x.trim())
    .filter(x => x.length >= 2 && !STOP.has(x));
}
function tokenSet(v) {
  return new Set(tokens(v));
}
function jaccard(a, b) {
  const A = a instanceof Set ? a : tokenSet(a);
  const B = b instanceof Set ? b : tokenSet(b);
  if (!A.size || !B.size) return 0;
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}
function sharedCount(a, b) {
  let n = 0;
  for (const x of a) if (b.has(x)) n++;
  return n;
}
function importantTokens(v) {
  return tokens(v).filter(x =>
    /\d/.test(x) || x.length >= 3
  );
}
function sameIssue(a, b) {
  if (a.section !== b.section) return false;
  if ((a.target || '') !== (b.target || '')) return false;
  if ((a.category || '') !== (b.category || '')) return false;

  const A = tokenSet(`${a.title} ${a.summary}`);
  const B = tokenSet(`${b.title} ${b.summary}`);
  const titleSim = jaccard(a.title, b.title);
  const allSim = jaccard(A, B);
  const shared = sharedCount(A, B);

  const impA = new Set(importantTokens(a.title));
  const impB = new Set(importantTokens(b.title));
  const sharedImportant = sharedCount(impA, impB);

  // 같은 사건 판단:
  // - 제목 유사도 0.42 이상
  // - 전체 토큰 유사도 0.34 이상
  // - 또는 중요 고유어·숫자 3개 이상 공유
  return titleSim >= 0.42 || allSim >= 0.34 || sharedImportant >= 3 || shared >= 5;
}

function processResults(job, source, results) {
  for (const r of results) {
    if (!r.title || !r.url) continue;
    const text = `${r.title} ${r.summary}`;

    if ((job.exclude_terms || []).some(term => contains(text, term))) continue;

    // CLIENT WATCH: target이 제목 또는 요약에 반드시 있어야 함
    if (job.section === 'CLIENT_WATCH' && job.target && !contains(text, job.target)) continue;

    // BUSINESS_WORK 관련성 강화:
    // 제목에 keyword/include term이 있거나, 전체 문장에서 관련어 2개 이상
    if (job.section === 'BUSINESS_WORK') {
      const titleKeyword = contains(r.title, job.keyword);
      const titleIncludeHits = (job.include_terms || []).filter(term => contains(r.title, term)).length;
      const bodyHits = [
        contains(text, job.keyword) ? job.keyword : null,
        ...(job.include_terms || []).filter(term => contains(text, term))
      ].filter(Boolean).length;

      if (!titleKeyword && titleIncludeHits === 0 && bodyHits < 2) continue;
    }

    let score = 0;

    if (job.target) {
      if (contains(r.title, job.target)) score += 45;
      else if (contains(r.summary, job.target)) score += 25;
    }

    if (job.keyword) {
      if (contains(r.title, job.keyword)) score += 30;
      else if (contains(r.summary, job.keyword)) score += 16;
    }

    let includeHitCount = 0;
    for (const term of (job.include_terms || [])) {
      if (contains(text, term)) {
        includeHitCount += 1;
        score += contains(r.title, term) ? 9 : 5;
      }
    }

    const age = daysAgo(r.published_at);
    // 검색엔진(Naver/Serper)의 날짜 필터가 항상 정확하게 걸러주는 게 아니라서
    // (오래된 기사가 재노출·재인덱싱되며 최근 검색 결과에 섞여 들어오는 경우가 있음),
    // 발행일이 확인되고 그게 분명히 대상 기간(최근 7일)을 크게 벗어나면
    // 점수와 무관하게 후보 자체에서 제외한다. 발행일을 못 읽은 경우(0)는 배제하지 않는다.
    if (r.published_at && age > 10) continue;
    if (age <= 2) score += 18;
    else if (age <= 4) score += 12;
    else if (age <= 7) score += 6;

    score += Math.max(0, 15 - Number(r.position || 99));
    if (source === 'NAVER' && job.section === 'CLIENT_WATCH') score += 8;

    candidates.push({
      job_id: job.job_id,
      section: job.section,
      category: job.category,
      target: job.target,
      keyword: job.keyword,
      title: r.title,
      url: r.url,
      summary: r.summary,
      published_at: r.published_at,
      source_name: r.source_name,
      search_source: source,
      include_hit_count: includeHitCount,
      score,
      period_start: job.period_start,
      period_end: job.period_end
    });
  }
}

for (const input of inputs) {
  const job = input.job || {};
  const naver = input.naver_response || {};
  const serper = input.serper_response || {};

  const naverResults = (Array.isArray(naver.items) ? naver.items : []).map((r, idx) => ({
    title: stripHtml(r.title),
    url: String(r.originallink || r.link || '').trim(),
    summary: stripHtml(r.description),
    published_at: r.pubDate || null,
    source_name: 'Naver News',
    position: idx + 1
  }));

  const serperResults = (Array.isArray(serper.news) ? serper.news :
                         Array.isArray(serper.organic) ? serper.organic : [])
    .map((r, idx) => ({
      title: stripHtml(r.title),
      url: String(r.link || r.url || '').trim(),
      summary: stripHtml(r.snippet || r.description),
      published_at: r.date || null,
      source_name: r.source || '',
      position: Number(r.position || idx + 1)
    }));

  processResults(job, 'NAVER', naverResults);
  processResults(job, 'SERPER', serperResults);
}

function normUrl(u) {
  return String(u || '')
    .replace(/#.*$/, '')
    .replace(/[?&](utm_[^=&]+|nclick)=[^&]*/gi, '')
    .replace(/[?&]$/, '')
    .replace(/\/$/, '');
}
function exactTitleKey(t) {
  return norm(t).replace(/[^0-9a-z가-힣]/g, '').slice(0, 70);
}

// 1차: URL·거의 동일 제목 제거
const exactMap = new Map();
for (const c of candidates.sort((a,b) => b.score - a.score)) {
  const key = `${c.section}|${normUrl(c.url)}|${exactTitleKey(c.title)}`;
  if (!exactMap.has(key)) {
    exactMap.set(key, {...c, found_in_sources: [c.search_source]});
  } else {
    const cur = exactMap.get(key);
    if (!cur.found_in_sources.includes(c.search_source)) {
      cur.found_in_sources.push(c.search_source);
      cur.score += 15;
    }
  }
}
const exactDeduped = [...exactMap.values()];

// 2차: 동일 사건 클러스터링
const clusters = [];
for (const article of exactDeduped.sort((a,b) => b.score - a.score)) {
  let cluster = clusters.find(c => sameIssue(c.representative, article));
  if (!cluster) {
    cluster = {
      representative: article,
      articles: [],
      urls: [],
      titles: [],
      sources: new Set(),
      total_score: 0
    };
    clusters.push(cluster);
  }

  cluster.articles.push(article);
  cluster.urls.push(article.url);
  cluster.titles.push(article.title);
  cluster.sources.add(article.source_name || article.search_source);
  cluster.total_score += article.score;

  if (article.score > cluster.representative.score) {
    cluster.representative = article;
  }
}

const allTopicItems = clusters.map((c, idx) => {
  const r = c.representative;
  const uniqueUrls = [...new Set(c.urls)].slice(0, 5);
  const uniqueTitles = [...new Set(c.titles)].slice(0, 5);
  const articleCount = c.articles.length;
  const sourceCount = c.sources.size;

  // 대표 요약은 점수가 높은 기사 2개의 요약을 중복 없이 결합
  const summaries = [...new Set(
    c.articles
      .sort((a,b) => b.score - a.score)
      .map(x => x.summary)
      .filter(Boolean)
  )].slice(0,2);

  return {
    topic_id: `${r.section}-${r.category || 'GENERAL'}-${String(idx+1).padStart(2,'0')}`,
    section: r.section,
    category: r.category,
    target: r.target,
    keyword: r.keyword,
    representative_title: r.title,
    combined_summary: summaries.join(' / ').slice(0, 200),
    article_count: articleCount,
    source_count: sourceCount,
    source_urls: uniqueUrls,
    source_titles: uniqueTitles,
    published_at: r.published_at,
    score: r.score + Math.min(20, (articleCount - 1) * 6) + Math.min(12, (sourceCount - 1) * 4),
    period_start: r.period_start,
    period_end: r.period_end,
    selection_basis: 'SCORE_PASS'
  };
}).sort((a,b) => b.score - a.score);

// 기본 품질 기준을 통과한 토픽
const qualifiedTopicItems = allTopicItems
  .filter(x => x.section !== 'CLIENT_WATCH' || x.score >= 55)
  .filter(x => x.section !== 'BUSINESS_WORK' || x.score >= 25)
  .sort((a,b) => b.score - a.score);

// 중요: 기존 버전은 "키워드별 후보 보장"이 점수 필터 뒤에서 작동해
// 점수 기준을 넘지 못한 키워드는 후보 풀에서 완전히 사라졌다.
// 이번 버전은 하드 관련성 필터를 통과한 allTopicItems에서 keyword별 최고 후보를
// 보완하되, 지나치게 약한 후보는 낮춘 fallback 점수 기준으로 한 번 더 제한한다.
function addKeywordFallbacks(qualified, allItems) {
  const result = [...qualified];
  const topicIds = new Set(result.map(x => x.topic_id));
  const represented = new Set(result.map(x => `${x.section}|${x.keyword}`));
  const bestBySectionKeyword = new Map();

  for (const item of allItems) {
    const key = `${item.section}|${item.keyword}`;
    if (!bestBySectionKeyword.has(key)) bestBySectionKeyword.set(key, item);
  }

  for (const [key, item] of bestBySectionKeyword.entries()) {
    if (represented.has(key) || topicIds.has(item.topic_id)) continue;

    const fallbackFloor = item.section === 'CLIENT_WATCH' ? 38 : 15;
    if (item.score < fallbackFloor) continue;

    result.push({ ...item, selection_basis: 'KEYWORD_FALLBACK' });
    represented.add(key);
    topicIds.add(item.topic_id);
  }

  return result.sort((a,b) => b.score - a.score);
}

const topicItems = addKeywordFallbacks(qualifiedTopicItems, allTopicItems);

// 3차: keyword·category 다양성 제한
function selectDiverse(items, maxTotal, maxPerKeyword, maxPerCategory) {
  const sorted = [...items].sort((a, b) => b.score - a.score);
  const selected = [];
  const selectedTopicIds = new Set();
  const keywordCounts = new Map();
  const categoryCounts = new Map();

  function addItem(item) {
    if (!item || selected.length >= maxTotal) return false;

    const topicId = item.topic_id || '';
    const keyword = item.keyword || 'NONE';
    const category = item.category || 'NONE';

    if (topicId && selectedTopicIds.has(topicId)) return false;
    if ((keywordCounts.get(keyword) || 0) >= maxPerKeyword) return false;
    if ((categoryCounts.get(category) || 0) >= maxPerCategory) return false;

    selected.push(item);
    if (topicId) selectedTopicIds.add(topicId);
    keywordCounts.set(keyword, (keywordCounts.get(keyword) || 0) + 1);
    categoryCounts.set(category, (categoryCounts.get(category) || 0) + 1);
    return true;
  }

  // 1차: 검색 결과가 존재하는 각 keyword의 최고 점수 후보를 1개씩 우선 확보한다.
  // 후보가 없는 keyword는 억지로 생성하지 않는다.
  const bestByKeyword = new Map();
  for (const item of sorted) {
    const keyword = item.keyword || 'NONE';
    if (!bestByKeyword.has(keyword)) bestByKeyword.set(keyword, item);
  }
  for (const item of bestByKeyword.values()) {
    if (selected.length >= maxTotal) break;
    addItem(item);
  }

  // 2차: 남은 자리는 전체 점수 순으로 채워 경쟁시킨다.
  for (const item of sorted) {
    if (selected.length >= maxTotal) break;
    addItem(item);
  }

  return selected;
}

function candidatePoolSize(items) {
  const keywordCount = new Set(
    items.map(x => String(x.keyword || '').trim()).filter(Boolean)
  ).size;

  // 기존 16개 상한은 유지하되, 활성 keyword가 더 많으면 최대 24개까지 확장한다.
  // 12개 CLIENT_WATCH / 20개 BUSINESS_WORK 구성에서는 각각 16개 / 20개 수준이다.
  return Math.min(24, Math.max(16, keywordCount));
}


// ─────────────────────────────────────────────
// 회사 맥락 문서(Google Docs) 읽기 - "2단계" 워크플로우와 동일 로직
// ─────────────────────────────────────────────
function extractTextFromGoogleDocsBody(body) {
  const chunks = [];
  const walk = (node) => {
    if (!node || typeof node !== 'object') return;
    if (node.textRun && typeof node.textRun.content === 'string') {
      chunks.push(node.textRun.content);
      return;
    }
    for (const key of Object.keys(node)) {
      const value = node[key];
      if (Array.isArray(value)) value.forEach(walk);
      else if (value && typeof value === 'object') walk(value);
    }
  };
  walk(body);
  return chunks.join('');
}

function pickGoogleDocText(obj) {
  if (typeof obj === 'string') return obj;
  if (!obj || typeof obj !== 'object') return '';
  if (typeof obj.content === 'string') return obj.content;
  if (typeof obj.text === 'string') return obj.text;
  if (typeof obj.data === 'string') return obj.data;
  if (typeof obj.body === 'string') return obj.body;
  if (obj.body && Array.isArray(obj.body.content)) return extractTextFromGoogleDocsBody(obj.body);
  if (Array.isArray(obj.content)) return extractTextFromGoogleDocsBody({ content: obj.content });
  return JSON.stringify(obj);
}

function cleanCompanyContext(text) {
  return String(text || '')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]+/g, ' ')
    .trim()
    .slice(0, 2000);
}

function looksLikeGoogleErrorOrHtml(text) {
  const s = String(text || '').slice(0, 2000);
  return (
    s.includes("window['ppConfig']") ||
    s.includes('페이지를 찾을 수 없음') ||
    s.includes('현재 파일을 열 수 없습니다') ||
    s.includes('<!DOCTYPE html') ||
    s.includes('<html') ||
    s.includes('Bad request') ||
    s.includes('The resource you are requesting could not be found')
  );
}

let googleDocJson = {};
try {
  googleDocJson = $('0-C. Google Docs - 회사 맥락 문서 읽기').item.json || {};
} catch (e) {
  googleDocJson = {};
}

const googleDocsNodeFailed = !!(googleDocJson.error || String(googleDocJson.message || '').includes('Bad request'));
let companyContextRaw = googleDocsNodeFailed ? '' : pickGoogleDocText(googleDocJson);
if (looksLikeGoogleErrorOrHtml(companyContextRaw)) companyContextRaw = '';

const companyContext = cleanCompanyContext(companyContextRaw) || `[회사 업무 맥락]
- 회사 맥락 문서를 불러오지 못했습니다. 이 경우 후보 자체의 사실관계만 기준으로 평가합니다.
- Google Docs 노드에 접근 권한이 있는 OAuth2 credential이 연결되어 있는지 확인하세요.`;

// 검색·평가 단계에서는 최종 뉴스레터 게재 수보다 넓게 DB에 축적한다.
// 후보가 충분한 경우 이 분기에서 최대 8개를 저장하고, 실제 뉴스레터 생성 단계에서 다시 4~6개로 압축한다.
const branchItems = topicItems.filter(x => x.section === branchSection);

const grouped = { CLIENT_WATCH: [], BUSINESS_WORK: [] };
grouped[branchSection] = selectDiverse(
  branchItems,
  candidatePoolSize(branchItems),
  3,
  6
);

const desiredCount = Math.min(8, grouped[branchSection].length);

if (!grouped[branchSection].length) {
  const firstJobForError = inputs.find(x => x.job?.job_id)?.job || {};
  throw new Error(
