// ========================================================
// 3-A-6. 구분자 기반 출력 결과 정리 + 행 분리
// JSON.parse를 아예 쓰지 않음 - 모델이 따옴표를 이스케이프할
// 필요가 없는 텍스트 포맷(##섹션 / FIELD: 값 / @@@ 구분자)을
// 줄 단위로 읽어서 파싱한다. JSON 문법 오류 자체가 발생할 수 없음.
// ========================================================

const base = $('3-B-10. Code - BUSINESS_WORK 후보 정리 + AI 평가 프롬프트').first().json;

const FIELD_KEY_MAP = {
  TOPIC_ID: 'topic_id',
  TITLE: 'title',
  SUMMARY: 'summary',
  IMPLICATION: 'implication',
  PRIORITY: 'priority',
  EVIDENCE_LEVEL: 'evidence_level',
  SOURCE_URLS: 'source_urls',
  SOURCE_TITLES: 'source_titles',
  CATEGORY: 'category',
  TARGET: 'target',
  KEYWORD: 'keyword'
};

function splitMulti(v) {
  return String(v || '')
    .split('||')
    .map(x => x.trim())
    .filter(Boolean);
}

function parseDelimitedOutput(rawText) {
  let text = String(rawText || '').trim();

  // 혹시 모델이 실수로 코드펜스를 붙였어도 무해하게 제거
  text = text.replace(/^```[a-zA-Z]*\s*/, '').replace(/```\s*$/, '').trim();

  const sections = { CLIENT_WATCH: [], BUSINESS_WORK: [] };
  let currentSection = null;
  let currentItem = null;
  let currentField = null;

  function flushItem() {
    if (currentItem && currentSection && Object.keys(currentItem).length) {
      sections[currentSection].push(currentItem);
    }
    currentItem = null;
    currentField = null;
  }

  const lines = text.split(/\r?\n/);

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line) continue;

    const upper = line.toUpperCase();

    if (upper === '##CLIENT_WATCH') {
      flushItem();
      currentSection = 'CLIENT_WATCH';
      continue;
    }
    if (upper === '##BUSINESS_WORK') {
      flushItem();
      currentSection = 'BUSINESS_WORK';
      continue;
    }
    if (line === '@@@') {
      flushItem();
      continue;
    }

    // "FIELD_NAME: 값" 형태 매칭 (콜론 앞은 대문자/언더바만 허용)
    const m = line.match(/^([A-Z_]+)\s*:\s*(.*)$/);
    if (m && FIELD_KEY_MAP[m[1]]) {
      if (!currentSection) continue; // 섹션 밖 잡음은 무시
      if (!currentItem) currentItem = {};
      currentField = FIELD_KEY_MAP[m[1]];
      currentItem[currentField] = m[2].trim();
      continue;
    }

    // 모델이 긴 문장을 줄바꿈한 경우: 직전 필드에 이어붙임
    if (currentItem && currentField) {
      currentItem[currentField] =
        `${currentItem[currentField]} ${line}`.trim();
    }
  }
  flushItem();

  function finalize(list) {
    return list
      .filter(it => it.title) // title 없는 항목은 파싱 실패로 간주
      .map(it => ({
        topic_id: it.topic_id || '',
        title: it.title || '',
        summary: it.summary || '',
        implication: it.implication || '',
        priority: it.priority || '',
        evidence_level: it.evidence_level || '',
        source_urls: splitMulti(it.source_urls),
        source_titles: splitMulti(it.source_titles),
        category: it.category || '',
        target: it.target || '',
        keyword: it.keyword || ''
      }));
  }

  return {
    client_watch: finalize(sections.CLIENT_WATCH),
    business_work: finalize(sections.BUSINESS_WORK)
  };
}

function getParsedOutput(json) {
  const rawText = (typeof json?.text === 'string' && json.text)
    ? json.text
    : (typeof json === 'string' ? json : '');

  if (!rawText) {
    throw new Error(
      'LLM 응답 텍스트를 찾지 못했습니다. ' +
      `수신 데이터: ${JSON.stringify(json).slice(0, 800)}`
    );
  }

  const parsed = parseDelimitedOutput(rawText);

  if (!parsed.client_watch.length && !parsed.business_work.length) {
    throw new Error(
      '구분자 포맷 파싱 결과가 비어 있습니다(모델이 형식을 안 지켰을 수 있음). ' +
      `원문(앞부분): ${rawText.slice(0, 800)}`
    );
  }

  return parsed;
}

function arr(value) {
  return Array.isArray(value) ? value : [];
}

function txt(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function num(value, fallback = 50) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function normalizeEvidence(value, urlCount = 0) {
  const evidence = txt(value).toUpperCase();

  if (['HIGH', 'MEDIUM', 'LOW'].includes(evidence)) {
    return evidence;
  }

  return urlCount >= 2 ? 'HIGH' : 'MEDIUM';
}

function normalizeUrls(value) {
  if (Array.isArray(value)) {
    return [...new Set(
      value.map(txt).filter(Boolean)
    )].slice(0, 5);
  }

  if (typeof value === 'string') {
    return [...new Set(
      value
        .split(/[\n,]+/)
        .map(x => x.trim())
        .filter(Boolean)
    )].slice(0, 5);
  }

  return [];
}

const parsed = getParsedOutput($json);

// 안전망: AI가 델리미터 포맷으로 URL을 다시 타이핑하는 과정에서
// 지어낼 가능성에 대비해, 실제 후보(3-A-7이 만든 grouped_candidates)에
// 있던 URL과 대조해서 없는 건 제거한다.
const verifiedUrlSet = new Set(
  Object.values(base.grouped_candidates || {})
    .flat()
    .flatMap(c => Array.isArray(c?.source_urls) ? c.source_urls.map(u => String(u).trim()) : [])
    .filter(Boolean)
);

function keepOnlyVerifiedUrls(urls) {
  return urls.filter(u => verifiedUrlSet.has(String(u).trim()));
}

const now = new Date().toISOString();
const periodStart = txt(base.period_start);
const periodEnd = txt(base.period_end);
const period = periodStart && periodEnd
  ? `${periodStart}~${periodEnd}`
  : '';

const output = [];
const usedTopicIds = new Set();
const categoryCounts = new Map();

function pushItems(items, section) {
  const sectionItems = arr(items).slice(0, 10);

  for (let index = 0; index < sectionItems.length; index++) {
    const item = sectionItems[index] || {};
    const category = txt(item.category) || 'GENERAL';
    const topicId =
      txt(item.topic_id) ||
      `${section}-${category}-${index + 1}`;

    const categoryKey = `${section}|${category}`;

    if (usedTopicIds.has(topicId)) continue;

    const currentCategoryCount =
      categoryCounts.get(categoryKey) || 0;

    if (currentCategoryCount >= 3) continue;

    const title = txt(item.title);
    const summary = txt(item.summary);
    const implication = txt(item.implication);

    if (!title || (!summary && !implication)) continue;

    const urls = keepOnlyVerifiedUrls(normalizeUrls(item.source_urls));

    usedTopicIds.add(topicId);
    categoryCounts.set(
      categoryKey,
      currentCategoryCount + 1
    );

    const sequence = output.length + 1;
    const randomCode = Math.random()
      .toString(36)
      .slice(2, 6)
      .toUpperCase();

    const dateCode = periodEnd
      ? periodEnd.replace(/-/g, '')
      : new Date()
          .toISOString()
          .slice(0, 10)
          .replace(/-/g, '');

    const itemId =
      `NLR-${dateCode}-${section}-${sequence}-${randomCode}`;

    const normalizedEvidence = normalizeEvidence(
      item.evidence_level,
      urls.length
    );

    const rawRecord = {
      topic_id: topicId,
      title,
      summary,
      implication,
      priority: num(item.priority),
      evidence_level: normalizedEvidence,
      source_urls: urls,
      source_titles: arr(item.source_titles)
        .map(txt)
        .filter(Boolean)
        .slice(0, 5),
      category,
      target: txt(item.target),
      keyword: txt(item.keyword)
    };

    output.push({
      json: {
        item_id: itemId,
        collected_at: now,
        research_period: period,
        section,
        source_pipeline: 'WEB_RESEARCH_TOPIC_CLUSTER',
        category,
        target: txt(item.target),
        keyword: txt(item.keyword),
        title,
        summary,
        implication,
        source_urls: urls.join('\n'),
        evidence_level: normalizedEvidence,
        priority: num(item.priority),
        raw_json: JSON.stringify(rawRecord)
      }
    });
  }
}

pushItems(parsed.client_watch, 'CLIENT_WATCH');
pushItems(parsed.business_work, 'BUSINESS_WORK');

if (!output.length) {
  throw new Error(
    '파싱은 성공했지만 저장할 항목이 없습니다. ' +
    `수신 데이터: ${JSON.stringify(parsed).slice(0, 1500)}`
  );
}

return output;

const rawMails = $input.all().map(x => x.json || {});

function decodeBase64Url(v) {
  if (!v) return '';
  try {
    let s = String(v).replace(/-/g, '+').replace(/_/g, '/');
    while (s.length % 4) s += '=';
    return Buffer.from(s, 'base64').toString('utf8');
  } catch {
    return '';
  }
}

function headerValue(headers, name) {
  const target = String(name).toLowerCase();
  const h = (Array.isArray(headers) ? headers : [])
    .find(x => String(x.name || '').toLowerCase() === target);
  return h ? String(h.value || '') : '';
}

function collectMimeParts(part, out = []) {
  if (!part || typeof part !== 'object') return out;

  const mime = String(part.mimeType || '').toLowerCase();
  const data = part.body?.data;

  if (data && (mime === 'text/plain' || mime === 'text/html')) {
    out.push({ mime, text: decodeBase64Url(data) });
  }

  if (data && !mime && part.body) {
    out.push({ mime: 'text/plain', text: decodeBase64Url(data) });
  }

  for (const child of (part.parts || [])) {
    collectMimeParts(child, out);
  }

  return out;
}

function decodeEntities(v) {
  return String(v || '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
}

function htmlToText(html) {
  return decodeEntities(String(html || ''))
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<(br|\/p|\/div|\/li|\/tr|\/h\d|\/td)>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\r/g, '');
}

function cleanBody(text) {
  let s = htmlToText(text)
    .replace(/\u200b/g, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  const footerPatterns = [
    /\n(?:수신거부|구독 해지|unsubscribe)\b/i,
    /\n(?:이 메일은 발신 전용|본 메일은 발신 전용)/i,
    /\n(?:copyright|all rights reserved)\b/i
  ];

  for (const re of footerPatterns) {
    const m = re.exec(s);
    if (m && m.index > 500) s = s.slice(0, m.index);
  }

  // 전체 본문은 디버깅·메타 추출용으로만 보존
  return s.slice(0, 15000);
}

function extractForwardedMeta(body) {
  return {
    sender:
      body.match(/(?:보낸사람|From)\s*:\s*([^\n]+)/i)?.[1]?.trim() || '',
    subject:
      body.match(/(?:제목|Subject)\s*:\s*([^\n]+)/i)?.[1]?.trim() || '',
    date:
      body.match(/(?:날짜|Date)\s*:\s*([^\n]+)/i)?.[1]?.trim() || ''
  };
}

function pickBody(m) {
  const directPlain =
    m.textPlain || m.text || m.bodyText || m.body?.text || '';
  const directHtml =
    m.textHtml || m.html || m.bodyHtml || m.body?.html || '';

  if (String(directPlain).trim().length > 200) {
    return {
      body: cleanBody(directPlain),
      html: String(directHtml || ''),
      source: 'DIRECT_TEXT'
    };
  }

  if (String(directHtml).trim().length > 200) {
    return {
      body: cleanBody(directHtml),
      html: String(directHtml),
      source: 'DIRECT_HTML'
    };
  }

  const payload = m.payload || m.message?.payload || {};
  const parts = collectMimeParts(payload);

  const plains = parts
    .filter(x => x.mime === 'text/plain')
    .map(x => x.text)
    .filter(Boolean);

  const htmls = parts
    .filter(x => x.mime === 'text/html')
    .map(x => x.text)
    .filter(Boolean);

  const plainCombined = plains.join('\n\n');
  const htmlCombined = htmls.join('\n\n');

  if (plainCombined.trim().length > 200) {
    return {
      body: cleanBody(plainCombined),
      html: htmlCombined,
      source: 'GMAIL_PAYLOAD_TEXT'
    };
  }

  if (htmlCombined.trim().length > 200) {
    return {
      body: cleanBody(htmlCombined),
      html: htmlCombined,
      source: 'GMAIL_PAYLOAD_HTML'
    };
  }

  return {
    body: cleanBody(m.snippet || m.message?.snippet || ''),
    html: '',
    source: 'SNIPPET_FALLBACK'
  };
}

function normalizeLine(v) {
  return String(v || '')
    .replace(/^[\s\-–—•·▪■◆▶▷►※★☆✨🔥📌💡🧠🛒🎬📱]+/u, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function isSystemLine(line) {
  return /^(from|to|date|subject|cc|bcc|보낸사람|받는사람|날짜|제목)\s*:/i.test(line) ||
    /^(unsubscribe|수신거부|구독 해지|광고|copyright|all rights reserved)/i.test(line) ||
    /^(---------- forwarded message ----------|전달된 메시지)/i.test(line);
}

// 이메일 본문에 흔한 긴 URL(구독 링크·클릭 트래킹 링크 등)은
// 트렌드 판단에 도움이 안 되면서 토큰만 잡아먹으므로 LLM 전달용 텍스트에서만 제거한다.
function stripUrlsForLLM(text) {
  return String(text || '')
    .split(/\n+/)
    .map(normalizeLine)
    .filter(x => x && !isSystemLine(x))
    .join('\n')
    .replace(/\[?https?:\/\/[^\s\]\)]+\]?/gi, '')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// 청크 하나의 최대 길이. 메일 본문이 이보다 길면 여러 조각(-p2, -p3...)으로
// 나눠서 전부 LLM에 전달한다(예산 안에서만 잘라 뒷부분을 통째로 버리지 않기 위함).
// cleanBody() 자체가 15000자에서 한 번 더 상한을 두고 있어, 조각 개수는 최대 3개 안팎이다.
const CHUNK_SIZE = 6000;

// 순수 관리성 메일(인증메일, 구독 감사 메일 등)은 트렌드 신호가 사실상 없는데도
// 예산만 차지해서, 캐릿처럼 "적은 수의 메일에 긴 트렌드가 몰려있는" 포맷의
// 뒷부분이 잘려나가는 원인이 된다. 이런 메일은 애초에 LLM 입력에서 제외한다.
const TRANSACTIONAL_SUBJECT_PATTERNS = [
  /인증\s*(메일|해\s*주세요|하기)/,
  /구독\s*(해\s*주셔서\s*감사|을\s*축하|신청.*완료)/,
  /회원\s*가입.*축하/,
  /환영합니다/
];
function isTransactionalMail(subject) {
  return TRANSACTIONAL_SUBJECT_PATTERNS.some(re => re.test(String(subject || '')));
}

// 뉴스레터에 흔한 협찬/광고성 콘텐츠 블록과, 링크에서 추출된 CTA 버튼 텍스트를
// LLM에 넘기기 전에 코드에서 최대한 걷어낸다. 트렌드 본문(예: "맥싱", "윔지" 설명)은
// 건드리지 않도록, 확실한 패턴(협찬 바이라인·구독자 이벤트 안내·짧은 버튼 문구)만 제거한다.
function stripAdContent(text) {
  let s = String(text || '');

  // "by. OOO" 협찬 바이라인 블록 제거 (본인 에디터 바이라인 "by. 에디터 OOO"는 실제 콘텐츠라 제외)
  // 종료 지점을 "\n\n / © / 끝"뿐 아니라 "👉 CTA문구" 줄도 인정한다 — 실제 데이터에서 추적용
  // URL이 200자 이상으로 길어서, 500자 안에 빈 줄이 안 나와 매칭 자체가 실패하는 경우가 있었다.
  s = s.replace(/by\.\s*(?!에디터)\S[^\n]{0,20}\n([\s\S]{0,1500}?(?:👉[^\n]{0,60}\n|\n\n|©|$))/g, '\n');

  // 구독자 혜택 / 이벤트 응모 / 당첨자 발표 안내 블록 (같은 이유로 종료 조건 보강)
  s = s.replace(/[^\n]{0,20}(구독자\s*혜택)[\s\S]{0,800}?(?:👉[^\n]{0,60}\n|\n\n|©|$)/g, '\n');
  s = s.replace(/(당첨자\s*발표|신청\s*방식\s*:)[\s\S]{0,400}?(?:\n\n|©|$)/g, '\n');

  // 짧은 CTA 버튼 텍스트로 추정되는 단독 줄 (링크에서 추출된 버튼 문구, 문장부호로 안 끝남)
  s = s.split('\n').filter(line => {
    const t = line.trim();
    if (!t) return true;
    const stripped = t.replace(/[👇🚀🎁🍿🍊✈️🍉🏊🎥📚⏰🔗]/g, '').trim();
    const isShortCta = stripped.length <= 24 &&
      /(받기|받아보기|가기|보기|배우기|신청하기|참여하기|다운받기|시작하기|만나요|살펴보기|눌러봐요?)$/.test(stripped) &&
      !/[.!?]$/.test(stripped);
    return !isShortCta;
  }).join('\n');

  return s.replace(/\n{3,}/g, '\n\n').trim();
}

const cleaned = rawMails.map((m, idx) => {
  const payload = m.payload || m.message?.payload || {};
  const headers = payload.headers || [];
  const picked = pickBody(m);
  const forwarded = extractForwardedMeta(picked.body);

  const subject = String(
    headerValue(headers, 'Subject') ||
    m.subject ||
    forwarded.subject ||
    ''
  );

  const from = String(
    headerValue(headers, 'From') ||
    m.from?.text ||
    m.from?.value?.[0]?.address ||
    m.sender ||
    forwarded.sender ||
    ''
  );

  const date = String(
    headerValue(headers, 'Date') ||
    m.date ||
    m.internalDate ||
    forwarded.date ||
    ''
  );

  // 광고성 문구를 먼저 걷어낸 뒤 URL/시스템 라인을 제거한다. 청크 분할 전이라
  // 여기서는 자르지 않고 전체(=cleanBody의 15000자 상한까지)를 보존한다.
  const bodyForLlm = stripUrlsForLLM(stripAdContent(picked.body));

  return {
    mail_id: String(m.id || m.messageId || m.message?.id || idx + 1),
    from,
    subject,
    date,
    body_source: picked.source,
    body_length: picked.body.length,
    payload_mime_type: String(payload.mimeType || ''),
    payload_part_count: Array.isArray(payload.parts) ? payload.parts.length : 0,
    body_for_llm: bodyForLlm
  };
});

const usable = cleaned.filter(x => x.body_length >= 300 && x.body_for_llm.length >= 100 && !isTransactionalMail(x.subject));

if (!cleaned.length) {
  throw new Error('Gmail 단건 조회 결과가 없습니다.');
