}

// 광고를 걷어내고도 여전히 CHUNK_SIZE보다 긴 메일은, 뒷부분을 버리지 않고
// 여러 조각(mail_id, mail_id-p2, mail_id-p3...)으로 나눠 전부 LLM에 전달한다.
// LLM에는 각 조각이 서로 다른 mail_id처럼 보이지만, 같은 원본 메일의 연속된 부분임을
// subject에 "(본문 N/M)"으로 표시해 문맥이 끊기지 않게 안내한다.
const llmMails = usable.flatMap(x => {
  const total = Math.max(1, Math.ceil(x.body_for_llm.length / CHUNK_SIZE));
  const parts = [];
  for (let i = 0; i < total; i++) {
    const chunkBody = x.body_for_llm.slice(i * CHUNK_SIZE, (i + 1) * CHUNK_SIZE);
    parts.push({
      mail_id: total > 1 ? `${x.mail_id}-p${i + 1}` : x.mail_id,
      from: x.from,
      subject: total > 1 ? `${x.subject} (본문 ${i + 1}/${total})` : x.subject,
      body: chunkBody
    });
  }
  return parts;
});

const prompt = `너는 젊은 세대의 소비·콘텐츠·직장생활·가치관 변화를 탐색하는 트렌드 리서처다.
