// 안전장치: AI가 search_query를 영어(원어) 문구로 써버리면 Naver/Serper 한국 뉴스 검색에서
// 결과가 거의 0건이 된다(실제로 확인된 문제: Maxxing/Touch grass/Whimsy 등 영어 트렌드명).
// 한글 비중이 낮으면 keyword의 괄호 앞 한글 표기로 대체하고, 그마저 없으면 원래 값을 그대로 쓴다.
function hasEnoughKorean(s) {
  const str = String(s || '');
  const koreanCount = (str.match(/[가-힣]/g) || []).length;
  const totalCount = str.replace(/\s/g, '').length;
  return totalCount > 0 && (koreanCount / totalCount) >= 0.3;
}
function koreanPortionOfKeyword(k) {
  return String(k || '').split(/[\(（]/)[0].trim();
}

return candidates.map((c, idx) => {
  const keyword = String(c.keyword || '').trim();
  let searchQuery = String(c.search_query || keyword || '').trim();
  if (!hasEnoughKorean(searchQuery)) {
    const fallback = koreanPortionOfKeyword(keyword);
    if (hasEnoughKorean(fallback)) searchQuery = fallback;
  }
  const qBase = searchQuery || keyword;
  const q = /트렌드/.test(qBase) ? qBase : `${qBase} 트렌드`;

  return {
    json: {
    candidate_id: `PC-${idx+1}`,
    keyword,
    search_query: searchQuery,
    what_is_happening: String(c.what_is_happening || ''),
    why_candidate: String(c.why_candidate || ''),
    mentioned_mail_ids: Array.isArray(c.mentioned_mail_ids) ? c.mentioned_mail_ids : [],
