  // 조합한 문구는, 실제 기사에서는 두 단어가 문장 안에 떨어져 등장하는 경우가 많다
  // (예: "촉감을 즐기는 굿즈로... 소비 트렌드"). 그래서 "구 전체가 붙어서 등장"을 요구하는 대신,
  // 트렌드·소비처럼 어디에나 붙는 일반 단어는 제외하고, 키워드에서 실제로 의미를 구분해주는
  // 단어들이 (순서·인접 여부와 무관하게) 전부 등장하는지만 확인한다.
  function stripSpaces(s) { return String(s || '').replace(/\s+/g, '').toLowerCase(); }
  const GENERIC_TOKENS = new Set(['트렌드','소비','문화','현상','라이프스타일','방식','신드롬','트랜드','열풍','유행','스타일','챌린지','밈']);
  function significantTokens(keyword) {
    // "터치 그래스(Touch grass)" → 괄호 앞 한글 표기만 사용 → ["터치","그래스"]
    const base = String(keyword || '').split(/[\(（]/)[0];
    return base.split(/\s+/).map(t => t.trim()).filter(t => t && !GENERIC_TOKENS.has(t));
  }
  const requiredTokens = significantTokens(job.keyword);
  function isTopicallyRelevant(x) {
    if (!requiredTokens.length) return true; // 키워드가 전부 일반 단어뿐이면 필터링을 건너뛴다
    const haystack = stripSpaces(x.title) + stripSpaces(x.snippet);
    return requiredTokens.every(t => haystack.includes(stripSpaces(t)));
  }

  // Naver + Serper 결과를 URL 기준으로 합치고 중복을 제거한 뒤, 실제로 키워드 구가 등장하는 것만 남긴다
  // (검색 적중률을 높이기 위해 두 소스를 함께 쓰되, 무관한 기사가 섞이지 않도록 관련성도 함께 검증).
  const seenUrls = new Set();
  const sources = [...naverSources, ...serperSources, ...snsSources]
    .filter(x => x.title && x.url)
    .filter(x => { if (seenUrls.has(x.url)) return false; seenUrls.add(x.url); return true; })
    .filter(isTopicallyRelevant)
    .slice(0,5);

  verified.push({
    keyword: job.keyword,
    search_query: job.search_query,
    email_signal: job.what_is_happening,
    candidate_reason: job.why_candidate,
    mentioned_mail_ids: job.mentioned_mail_ids,
    initial_evidence_level: job.initial_evidence_level,
    web_sources: sources
  });
}

const validVerified = verified.filter(x =>
  String(x.keyword || '').trim() ||
  String(x.email_signal || '').trim()
);

const desiredCount = Math.min(8, validVerified.length);

if (!desiredCount) {
  throw new Error('PEOPLE_CULTURE 최종 분석 후보가 없습니다. 메일 후보 추출 또는 웹 검증 Job 전달 상태를 확인하세요.');
}

const prompt = `너는 CL4 이상 보직자(센터장·그룹장·사업부장·임원)에게 젊은 구성원의 행동과 가치관을 조직 운영 관점에서 해석해주는 PEOPLE & CULTURE 편집자다.
이메일에서 발견한 후보와 최근 7일 웹검색 결과를 함께 검토하라.

[목표]
- 이번 단계는 최종 뉴스레터 선별이 아니라 2단계에서 사용자가 선택할 후보를 저장하는 단계다.
- 트렌드 자체를 소개하는 데서 그치지 않는다. 이 섹션의 존재 이유는 "요즘 애들 사이에서 이런 게 유행한다더라"를 전달하는 게 아니라, 보직자가 조직 운영(채용, 유지, 복리후생, 조직문화, 세대 간 소통, 근무 제도 등) 관점에서 실제로 참고할 수 있는 해석을 제공하는 것이다.
- 입력된 유효 후보 ${desiredCount}개를 반드시 정확히 ${desiredCount}개 출력한다. 후보가 충분한데 임의로 1~2개에서 멈추지 않는다.
- 최신성과 다양성을 우선하되, 명백한 중복·광고·정치 및 사건 속보가 아니라면 후보를 지나치게 엄격하게 제거하지 않는다.
- 웹검색 근거가 충분하면 HIGH 또는 MEDIUM으로, 웹 근거가 약하더라도 이메일에서 반복 언급되거나 구체적인 행동·상품·콘텐츠 사례가 확인되면 LOW로 포함할 수 있다.
- 웹검색 결과가 없다는 이유만으로 이메일 기반 후보를 자동 제외하지 않는다. 이 경우 source_urls는 빈 배열로 두고 evidence_level은 LOW로 설정한다.
- 이메일 문장을 그대로 베끼지 말고 이메일 신호와 웹검색 결과를 함께 반영해 독립적으로 작성한다.
- 사실과 해석을 구분한다.
- summary(트렌드 설명)는 2~3문장으로 작성한다. 입력 후보 또는 웹검색 결과에 실제로 있는 구체적인 행동·상품명·브랜드명·하위 트렌드명을 최소 1개 포함하고, 가능하면 확산 정도를 보여주는 근거(언급량 증가율, 관련 상품 출시 사례, 특정 세대·집단의 비중 등 원문에 있는 경우)도 함께 담는다. 입력에 없는 사례를 새로 만들지 않는다.
- organization_view(조직 운영 시사점)는 절대 비워두거나 한 줄로 얼버무리지 않는다. 이 트렌드가 왜 지금 나타났는지에 대한 심리적·사회적 배경을 한 문장으로 짚고, 그것이 채용·유지·조직문화·근무 제도·세대 간 소통·복리후생 설계 중 어디에 어떤 시사점을 주는지 최소 2문장으로 구체적으로 작성한다. "~에 참고할 필요가 있습니다" 같은 상투적 마무리 대신, 무엇을 검토하거나 시도해볼 수 있는지까지 짚는다. 정말로 회사 운영과 연결 지을 근거가 전혀 없는 극히 예외적인 경우에만 그 이유를 한 문장으로 명시하고 짧게 쓴다 (비워두지 않는다).
- 가능하면 직장생활·조직문화, 소비·라이프스타일, 콘텐츠·SNS·여가, 세대 가치관·커리어 영역을 분산한다.
- 젊은 세대 전체를 단정하지 말고 '일부 젊은 층', '최근 관찰되는 흐름' 등 신중한 표현을 사용한다. 다만 organization_view의 결론 자체는 신중하되 분명하게 제시한다.
- source_urls는 반드시 [후보 및 웹 검증]의 web_sources에 실제로 나열된 url 문자열을 그대로 복사해서만 사용한다. 절대 URL을 새로 만들거나, 알고 있는 것 같은 URL을 추측해서 채우지 마라. 이건 심각한 오류이며 사용자에게 실제 접속 불가능한 링크를 보여주는 결과로 이어진다.
- web_sources에 있다고 해서 전부 관련 자료는 아니다. 제목과 요약을 실제로 읽고, 이 키워드/트렌드를 다루는 기사인지 먼저 판단하라. 단어만 우연히 겹치고 실제 주제가 다른 기사(예: 키워드가 '걸 그립'인데 골프 그립이나 게임 기사가 섞여 들어온 경우)는 web_sources에 있어도 source_urls에서 반드시 제외한다.
- 특정 후보의 web_sources가 비어있거나 관련된 URL이 없으면, source_urls는 반드시 빈 배열([])로 남긴다. 빈 배열도 정상적인 결과이며, 억지로 채우는 것보다 훨씬 낫다.
- 반드시 JSON 객체만 출력한다.\n- 배열의 객체 사이에는 반드시 쉼표를 넣는다.\n- 문자열 안의 큰따옴표는 반드시 \\\"로 이스케이프한다.\n- 후행 쉼표와 주석을 사용하지 않는다.

[출력]
{
  "people_culture": [
    {
      "title": "",
      "summary": "",
      "organization_view": "",
      "keyword": "",
      "priority": 0,
      "evidence_level": "HIGH|MEDIUM|LOW",
      "source_urls": [""],
      "mentioned_mail_ids": [""]
    }
  ]
}

[후보 및 웹 검증]
${JSON.stringify(validVerified, null, 2)}`;

return [{
  json: {
    period_start: packed[0]?.job?.period_start || '',
    period_end: packed[0]?.job?.period_end || '',
    original_candidate_count: verified.length,
    valid_candidate_count: validVerified.length,
    desired_output_count: desiredCount,
    verified_candidates: validVerified,
    prompt
  }
}];

const base = $('3-C-10. Code - 웹 검증 취합 + 최종 분석 프롬프트').first().json;
const raw = $json.text || $json.output || $json.response || $json.result || '';


function repairJsonText(input) {
  let s = String(input || '')
    .replace(/^\uFEFF/, '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();

  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first >= 0 && last >= first) s = s.slice(first, last + 1);

  // 흔한 LLM JSON 오류 정리
  s = s
    .replace(/\bNone\b/g, 'null')
    .replace(/\bTrue\b/g, 'true')
    .replace(/\bFalse\b/g, 'false')
    .replace(/,\s*([}\]])/g, '$1')
    .replace(/}\s*{/g, '},{')
    .replace(/]\s*\[/g, '],[')
    .replace(/}\s*"/g, '},"')
    .replace(/]\s*"/g, '],"')
    .replace(/"(\s+)"/g, '",$1"');

  // 문자열 안의 실제 개행·탭을 JSON escape로 교체
  let out = '';
  let inString = false;
  let escaped = false;

  for (let i = 0; i < s.length; i++) {
    const ch = s[i];

    if (inString) {
      if (escaped) {
        out += ch;
        escaped = false;
        continue;
      }
      if (ch === '\\') {
        out += ch;
        escaped = true;
        continue;
      }
      if (ch === '"') {
        inString = false;
        out += ch;
        continue;
      }
      if (ch === '\n') {
        out += '\\n';
        continue;
      }
      if (ch === '\r') continue;
      if (ch === '\t') {
        out += '\\t';
        continue;
      }
      out += ch;
    } else {
      if (ch === '"') inString = true;
      out += ch;
    }
  }

  return out;
}

function parseJsonRobust(v) {
  if (v && typeof v === 'object') return v;

  const original = String(v || '');
  const repaired = repairJsonText(original);

  try {
    return JSON.parse(repaired);
  } catch (firstError) {
    // 객체 사이 쉼표 누락을 한 번 더 넓게 보정
    const secondPass = repaired
      .replace(/}\s*,?\s*(?={)/g, '},')
      .replace(/]\s*,?\s*(?="(?:client_watch|business_work|people_culture|trend_candidates)")/g, '],');

    try {
      return JSON.parse(secondPass);
    } catch (secondError) {
      throw new Error(
        `${secondError.message} | RAW_PREVIEW=${original.slice(0, 1800)}`
      );
    }
  }
}

let parsed;
try { parsed=parseJsonRobust(raw); }
catch(e) { throw new Error(`3-C 최종 JSON 파싱 실패: ${e.message}`); }

const list = Array.isArray(parsed.people_culture) ? parsed.people_culture.slice(0,8) : [];
if (!list.length) throw new Error('PEOPLE & CULTURE 최종 항목이 없습니다.');

// 안전망: AI가 프롬프트를 어기고 URL을 지어낸 경우를 대비해,
// 실제로 웹 검증(Serper)이 반환한 URL 목록과 대조해서 없는 건 전부 버린다.
const verifiedUrlSet = new Set(
  (Array.isArray(base.verified_candidates) ? base.verified_candidates : [])
    .flatMap(c => Array.isArray(c.web_sources) ? c.web_sources.map(s => String(s.url || '').trim()) : [])
    .filter(Boolean)
);

function keepOnlyVerifiedUrls(urls) {
  return urls
    .map(u => String(u).trim())
    .filter(u => u && verifiedUrlSet.has(u));
}

const now = new Date().toISOString();
const period = `${base.period_start}~${base.period_end}`;

return list.map((x, idx) => {
  const rawUrls = Array.isArray(x.source_urls) ? x.source_urls.map(String).filter(Boolean) : [];
  const urls = keepOnlyVerifiedUrls(rawUrls);
  const itemId = `NLR-${base.period_end.replace(/-/g,'')}-PEOPLE_CULTURE-${idx+1}-${Math.random().toString(36).slice(2,6).toUpperCase()}`;
  const rawRecord = {
    ...x,
    mentioned_mail_ids: Array.isArray(x.mentioned_mail_ids) ? x.mentioned_mail_ids : []
  };
  return {
    json: {
      item_id: itemId,
      collected_at: now,
      research_period: period,
      section: 'PEOPLE_CULTURE',
      source_pipeline: 'EMAIL_TREND_WEB_VERIFY',
      category: 'PEOPLE_CULTURE',
      target: '',
      keyword: String(x.keyword || ''),
      title: String(x.title || ''),
      summary: String(x.summary || ''),
      implication: String(x.organization_view || ''),
      source_urls: urls.join('\n'),
      evidence_level: ['HIGH','MEDIUM','LOW'].includes(String(x.evidence_level || '').toUpperCase()) ? String(x.evidence_level).toUpperCase() : 'MEDIUM',
      priority: Number(x.priority || 50),
      raw_json: JSON.stringify(rawRecord)
    }
  };
});

const jobs = $('3-C-5. Code - 후보 JSON 정리 + 검증 검색 Job').all();
const job = jobs[$itemIndex]?.json || {};

if (!job.candidate_id) {
  throw new Error(
    'PEOPLE_CULTURE Naver 결과 Job 복원 실패: 입력 인덱스 ' + $itemIndex +
    ', 조회된 Job=' + JSON.stringify(job).slice(0, 500)
  );
}

return {
  json: {
    job,
    naver_response: $json || {}
  },
  pairedItem: { item: $itemIndex }
};

function stripSpaces(s) { return String(s || '').replace(/\s+/g, '').toLowerCase(); }
const GENERIC_TOKENS = new Set(['트렌드','소비','문화','현상','라이프스타일','방식','신드롬','트랜드','열풍','유행','스타일','챌린지','밈']);
function significantTokens(keyword) {
  const base = String(keyword || '').split(/[\(（]/)[0];
  return base.split(/\s+/).map(t => t.trim()).filter(t => t && !GENERIC_TOKENS.has(t));
}
function hasRelevantMatch(keyword, items) {
  const requiredTokens = significantTokens(keyword);
  if (!requiredTokens.length) return true;
  return items.some(it => {
    const haystack = stripSpaces(it.title) + stripSpaces(it.description || it.snippet);
    return requiredTokens.every(t => haystack.includes(stripSpaces(t)));
  });
}

const job = $json.job || {};
const naverItems = Array.isArray($json.naver_response?.items) ? $json.naver_response.items : [];
const serperNewsItems = Array.isArray($json.serper_response?.news) ? $json.serper_response.news : [];

const hasRelevantNews = hasRelevantMatch(job.keyword, [...naverItems, ...serperNewsItems]);

return {
  json: {
    ...$json,
    has_relevant_news: hasRelevantNews
  }
};

const prior = $('3-C-8-2. IF - 뉴스에서 관련 자료 못 찾음').item.json;

// SNS 검색 결과에도 imageUrl 등 불필요한 대용량 필드가 섞여올 수 있어 미리 제거한다.
const snsRaw = $json || {};
if (Array.isArray(snsRaw.organic)) {
  for (const item of snsRaw.organic) {
    delete item.imageUrl;
    delete item.imageBase64;
    delete item.thumbnail;
  }
}

return {
  json: {
    ...prior,
    sns_response: snsRaw
  }
};
